function WeatherPanel() {
  const [city, setCity] = React.useState('REPLACE_WITH_CITY');
  const [weather, setWeather] = React.useState(null);
  const [loading, setLoading] = React.useState(false);

  React.useEffect(() => {
    if (!city) return;
    setLoading(true);
    fetch(`https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(city)}&count=1`)
      .then(r=>r.json())
      .then(geo=>{
        const lat = geo.results?.[0]?.latitude;
        const lon = geo.results?.[0]?.longitude;
        if (!lat) return setLoading(false);
        return fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current=temperature_2m,weather_code&daily=temperature_2m_max,temperature_2m_min,weather_code&timezone=auto`);
      })
      .then(r=>r?.json())
      .then(d=>{setWeather(d);setLoading(false);})
      .catch(()=>setLoading(false));
  }, [city]);

  const wmo = {0:'☀️',1:'🌤️',2:'⛅',3:'☁️',45:'🌫️',48:'🌫️',51:'🌧️',53:'🌧️',55:'🌧️',61:'🌧️',63:'🌧️',65:'🌧️',71:'❄️',73:'❄️',75:'❄️',95:'⛈️'};

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',gap:8,marginBottom:12}}>
        <input value={city} onChange={e=>setCity(e.target.value)} onKeyDown={e=>e.key==='Enter'&&setCity(e.target.value)}
          style={{flex:1,padding:'8px 12px',borderRadius:8,border:'1px solid #ccc',fontSize:14}}
          placeholder="City name…"/>
        <button onClick={()=>setCity(city)}
          style={{padding:'8px 16px',borderRadius:8,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer'}}>
          Search
        </button>
      </div>
      {loading && <div style={{textAlign:'center',color:'#888'}}>Loading…</div>}
      {weather && (
        <div style={{flex:1}}>
          <div style={{textAlign:'center',marginBottom:16}}>
            <div style={{fontSize:48}}>{wmo[weather.current?.weather_code] || '🌡️'}</div>
            <div style={{fontSize:36,fontWeight:200}}>{weather.current?.temperature_2m}°C</div>
          </div>
          <div style={{display:'flex',gap:8,overflow:'auto'}}>
            {weather.daily?.time?.slice(0,5).map((t,i)=> (
              <div key={i} style={{flex:1,textAlign:'center',padding:8,background:'#f5f5f5',borderRadius:8,minWidth:60}}>
                <div style={{fontSize:11,color:'#888'}}>{new Date(t).toLocaleDateString('en',{weekday:'short'})}</div>
                <div style={{fontSize:20}}>{wmo[weather.daily.weather_code[i]] || '🌡️'}</div>
                <div style={{fontSize:12}}>{weather.daily.temperature_2m_max[i]}° / {weather.daily.temperature_2m_min[i]}°</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
render(<WeatherPanel/>);
